      {/* Modal Content */}
      <div className="relative bg-white rounded-2xl shadow-2xl w-full max-w-sm max-h-[70vh] overflow-y-auto flex flex-col animate-[fadeIn_0.2s_ease-out]">
        <button 
          onClick={onClose}
          className="absolute top-3 right-3 z-10 w-8 h-8 flex items-center justify-center bg-white/80 rounded-full text-charcoal hover:bg-gray-100 transition-colors"
        >
          ✕
        </button>

        <div className="relative aspect-square bg-gray-50 flex-shrink-0">
          <img 
            src={product.imageUrl} 
            alt={product.name} 
            className="w-full h-full object-cover"
          />
          <div className="absolute bottom-4 left-4">
             <span className="bg-navy text-white px-3 py-1 text-xs font-bold uppercase tracking-wider rounded-md shadow-lg">
               {product.category}
             </span>
          </div>
        </div>

        <div className="p-6">
          <div className="flex justify-between items-start mb-2">
            <h2 className="font-serif text-2xl text-navy leading-tight">{product.name}</h2>
            <span className="text-xl font-medium text-orange ml-4 whitespace-nowrap">{product.priceDisplay}</span>
          </div>

          <div className="w-12 h-0.5 bg-gray-200 my-4" />

          <p className="text-gray-600 leading-relaxed text-sm mb-8">
            {product.description}
          </p>

          <Button 
            fullWidth 
            size="lg" 
            variant="primary" 
            onClick={handleBuy}
            className="shadow-lg shadow-navy/20 gap-2"
          >
            <span>{ICONS.SHOP}</span> Buy Now
          </Button>

          <p className="text-[10px] text-center text-gray-400 mt-4">
            You will be redirected to the CoreKaya secure checkout.
          </p>
        </div>
      </div>
    </div>
  );
};

import { GoogleGenAI } from "@google/genai";

const apiKey = process.env.API_KEY || ''; 
// NOTE: In a real app, ensure this environment variable is set. 
// For this demo, it relies on the system having the key available.

const ai = new GoogleGenAI({ apiKey });

export const generateWellnessTip = async (mood: string, energy: string): Promise<string> => {
  try {
    const model = 'gemini-2.5-flash';
    const prompt = `
      Act as a high-end Pilates and Wellness coach for CoreKaya Labs. 
      The user is feeling "${mood}" with "${energy}" energy levels.
      Provide a concise, motivating 2-sentence tip focusing on either a mindset shift, a small movement to try, or a nutritional suggestion.
      Keep the tone elegant, encouraging, and scientific.
    `;

    const response = await ai.models.generateContent({
      model,
      contents: prompt,
    });

    return response.text.trim();
  } catch (error) {
    console.error("AI Error", error);
    return "Listen to your body today. Movement is medicine, and rest is repair.";
  }
};

export const askAiCoach = async (question: string): Promise<string> => {
  try {
     const model = 'gemini-2.5-flash';
     const response = await ai.models.generateContent({
      model,
      contents: `You are the AI Coach for CoreKaya Pilates. Answer this user question briefly (max 50 words): ${question}`,
    });
    return response.text.trim();
  } catch (error) {
    return "I'm having trouble connecting to the CoreKaya mainframe right now.";
  }
}

export const generateSessionPlan = async (
  equipment: string[],
  mood: string,
  issues: string[],
  customNote: string
): Promise<string> => {
  try {
    const model = 'gemini-2.5-flash';

    const systemPrompt = `
      SYSTEM ROLE:
      You are a Master Pilates Educator with 40+ years of international teaching experience,
      combined with a Senior Product Architect designing instructor-grade fitness intelligence systems.

      You represent the collective wisdom of elite Pilates teachers who specialize in:
      Reformer, Cadillac, Trapeze, Wunda Chair, Ladder Barrel, Spine Corrector, and Advanced Mat work.

      You DO NOT generate motivational content.
      You DO NOT generate beginner explanations.
      You DO NOT suggest watching videos.

      You generate STRUCTURED, PROFESSIONAL, CLASS-READY PILATES SESSION PLANS.

      ---

      PROJECT CONTEXT:
      This feature is called **AI Coach – Instructor Mode** inside the CoreKaya / YoKalp App.

      Primary Goal:
      To STANDARDIZE class quality across all YoKalp studios by guiding instructors
      to design **safe, intelligent, progressive, and professional Pilates sessions**.

      ---

      ## 🔹 UX RULE (VERY IMPORTANT)
      The user WILL NOT type any prompt.
      The AI must generate output ONLY based on structured UI selections.

      ---

      ## 🔹 INPUT DATA
      EQUIPMENT AVAILABLE: ${equipment.join(', ')}
      SESSION MOOD/INTENT: ${mood}
      CLIENT ISSUES/CONSIDERATIONS: ${issues.join(', ')}
      CUSTOM NOTES: ${customNote}

      ---

      ## 🔹 OUTPUT REQUIREMENTS (VERY STRICT)

      You must generate a **COMPLETE PILATES SESSION PLAN** as if designed by a
      highly experienced YoKalp Master Instructor.

      ### STRUCTURE THE OUTPUT EXACTLY LIKE THIS:

      ---

      ### 🧠 SESSION OVERVIEW
      • Session Type: (e.g., Advanced Reformer Flow)
      • Target Duration: (e.g., 50–60 minutes)
      • Primary Focus: (Strength / Mobility / Control etc.)
      • Teaching Intention: (What the instructor should emphasize)

      ---

      ### 🔸 PHASE 1: PREPARATION / WARM-UP
      For each exercise:
      • Exercise Name
      • Equipment Used
      • Purpose (Why this comes first)
      • Key Teaching Cues
      • Breathing Focus

      (Use bullet points, not paragraphs)

      ---

      ### 🔸 PHASE 2: MAIN WORK SEQUENCE
      Divide into logical blocks if needed:
      • Block A – Strength
      • Block B – Control
      • Block C – Flow / Athletic Integration

      For EACH exercise include:
      • Exercise Name
      • Spring / Resistance suggestion (if applicable)
      • Execution Notes (tempo, alignment, control)
      • Instructor Observation Tips
      • Common Mistakes to Watch

      ---

      ### 🔸 PHASE 3: INTEGRATION / CHALLENGE (if mood allows)
      Only include if the selected mood supports it.

      • Advanced transitions
      • Athletic or coordination-based work
      • Optional challenge variations

      ---

      ### 🔸 PHASE 4: COOL DOWN / RESET
      • Decompression exercises
      • Spine neutralization
      • Nervous system calming
      • Breath integration

      ---

      ### 🧩 MODIFICATIONS & SAFETY NOTES
      • Clear guidance based on selected issues: ${issues.join(', ')}
      • What to avoid
      • What to emphasize instead

      ---

      ### 🎯 INSTRUCTOR REMINDERS
      Short bullet points like:
      • “Quality over quantity”
      • “Watch rib flare during fatigue”
      • “Reduce springs if form deteriorates”

      ---

      ## 🔹 LANGUAGE & TONE RULES
      • Professional
      • Calm
      • Instructor-to-instructor tone
      • No emojis
      • No marketing language
      • No beginner explanations

      ---

      ## 🔹 PHILOSOPHY
      This is NOT entertainment.
      This is NOT content consumption.
      This is **Pilates intelligence, systemized**.
      The output should feel like:
      👉 A senior instructor standing next to you, quietly guiding your class design.
    `;

    const response = await ai.models.generateContent({
      model,
      contents: systemPrompt,
    });

    return response.text.trim();
  } catch (error) {
    console.error("AI Instructor Mode Error", error);
    return "Error generating session plan. Please check your connection and try again.";
  }
};

import React, { useState } from 'react';
import { generateWellnessTip, askAiCoach, generateSessionPlan } from '../services/geminiService';
import { Button } from '../components/Button';
import { ICONS } from '../constants';

type Mode = 'concierge' | 'instructor';

// --- DATA CONSTANTS ---
const EQUIPMENT_OPTIONS = [
  'Mat',
  'Reformer',
  'Reformer with Tower',
  'Full Cadillac',
  'Wunda Chair',
  'Ladder Barrel',
  'Spine Corrector',
  'Jumpboard',
  'Accessories (Magic Circle, Ball, Bands, Weights)'
];

const MOOD_OPTIONS = [
  'Calm & Centered',
  'Energizing',
  'Athletic / Performance',
  'Strength Focused',
  'Mobility & Flexibility',
  'Recovery / Restoration',
  'Challenging & Advanced'
];

const ISSUE_OPTIONS = [
  'Lower back discomfort',
  'Cervical / neck stiffness',
  'Knee sensitivity',
  'Shoulder limitation',
  'Postural imbalance',
  'Diabetes',
  'High stress / fatigue'
];

export const AiCoach: React.FC = () => {
  const [mode, setMode] = useState<Mode>('concierge');

  // Concierge State
  const [tip, setTip] = useState<string | null>(null);
  const [loadingTip, setLoadingTip] = useState(false);
  const [conciergeQuestion, setConciergeQuestion] = useState("");
  const [conciergeAnswer, setConciergeAnswer] = useState("");
  const [loadingConcierge, setLoadingConcierge] = useState(false);

  // Instructor Mode State
  const [equipment, setEquipment] = useState<string[]>([]);
  const [mood, setMood] = useState<string>("");
  const [issues, setIssues] = useState<string[]>([]);
  const [customNote, setCustomNote] = useState("");
  const [sessionPlan, setSessionPlan] = useState<string | null>(null);
  const [loadingPlan, setLoadingPlan] = useState(false);

  // --- HANDLERS ---

  const handleGetDailyTip = async () => {
    setLoadingTip(true);
    const result = await generateWellnessTip("motivated", "moderate");
    setTip(result);
    setLoadingTip(false);
  };

  const handleAskConcierge = async () => {
      if(!conciergeQuestion.trim()) return;
      setLoadingConcierge(true);
      const res = await askAiCoach(conciergeQuestion);
      setConciergeAnswer(res);
      setLoadingConcierge(false);
  }

  const toggleSelection = (item: string, list: string[], setList: (l: string[]) => void) => {
    if (list.includes(item)) {
      setList(list.filter(i => i !== item));
    } else {
      setList([...list, item]);
    }
  };

  const handleGeneratePlan = async () => {
    if (equipment.length === 0 || !mood) {
      alert("Please select at least one piece of equipment and a session mood.");
      return;
    }
    setLoadingPlan(true);
    const result = await generateSessionPlan(equipment, mood, issues, customNote);
    setSessionPlan(result);
    setLoadingPlan(false);
  };

  // --- RENDERERS ---

  // Simple Markdown-ish parser for the Plan output
  const renderPlanOutput = (text: string) => {
    return text.split('\n').map((line, idx) => {
      const trimmed = line.trim();
      if (trimmed.startsWith('### ')) {
        return <h3 key={idx} className="font-serif text-xl text-navy mt-6 mb-3 font-bold border-b border-gray-200 pb-1">{trimmed.replace('### ', '')}</h3>;
      }
      if (trimmed.startsWith('## ')) {
        return <h2 key={idx} className="font-serif text-2xl text-navy-dark mt-8 mb-4 font-bold">{trimmed.replace('## ', '')}</h2>;
      }
      if (trimmed.startsWith('•')) {
        return <li key={idx} className="ml-4 pl-2 text-charcoal/90 mb-1 leading-relaxed list-none relative before:content-['•'] before:absolute before:left-[-1em] before:text-orange">{trimmed.replace('•', '').trim()}</li>;
      }
      if (trimmed.startsWith('👉')) {
          return <p key={idx} className="bg-sand-dark p-4 rounded-lg italic text-navy border-l-4 border-navy my-4">{trimmed}</p>;
      }
      if (trimmed === '---') {
        return <hr key={idx} className="border-gray-100 my-4" />;
      }
      if (trimmed === '') {
        return <div key={idx} className="h-2"></div>;
      }
      return <p key={idx} className="text-charcoal leading-relaxed mb-1">{line}</p>;
    });
  };

  return (
    <div className="min-h-screen bg-sand pb-24 px-6 pt-8">

      {/* Mode Switcher */}
      <div className="flex bg-white p-1 rounded-xl shadow-sm mb-8 sticky top-4 z-30 border border-gray-100">
        <button 
          onClick={() => setMode('concierge')}
          className={`flex-1 py-2.5 rounded-lg text-sm font-bold transition-all ${mode === 'concierge' ? 'bg-navy text-white shadow-md' : 'text-gray-400 hover:text-navy'}`}
        >
          Concierge
        </button>
        <button 
          onClick={() => setMode('instructor')}
          className={`flex-1 py-2.5 rounded-lg text-sm font-bold transition-all ${mode === 'instructor' ? 'bg-navy text-white shadow-md' : 'text-gray-400 hover:text-navy'}`}
        >
          Instructor Mode
        </button>
      </div>

      {mode === 'concierge' ? (
        <div className="animate-[fadeIn_0.3s_ease-out]">
            <h1 className="font-serif text-3xl text-charcoal mb-2">AI Concierge</h1>
            <p className="text-gray-500 mb-8">Your personalized wellness intelligence.</p>

            {/* Daily Insight Card */}
            <div className="bg-navy text-white p-6 rounded-2xl shadow-lg mb-8 relative overflow-hidden">
                <div className="relative z-10">
                    <h2 className="font-serif text-xl mb-4 flex items-center gap-2">
                        {ICONS.FIRE} Daily Insight
                    </h2>
                    {tip ? (
                    <p className="font-sans text-lg leading-relaxed italic opacity-90">"{tip}"</p>
                    ) : (
                    <div className="text-center py-4">
                        <Button onClick={handleGetDailyTip} variant="ghost" className="text-white bg-white/20 hover:bg-white/30 border border-white/20">
                        {loadingTip ? 'Connecting...' : 'Reveal Today\'s Wisdom'}
                        </Button>
                    </div>
                    )}
                </div>
                {/* Background Decor */}
                <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-full -translate-y-1/2 translate-x-1/2 blur-2xl"></div>
            </div>

            {/* Ask Question Section */}
            <div className="bg-white p-6 rounded-2xl shadow-sm">
                <h3 className="font-serif text-lg mb-4 text-charcoal">Ask the Labs</h3>
                <textarea
                    value={conciergeQuestion}
                    onChange={(e) => setConciergeQuestion(e.target.value)}
                    placeholder="e.g., How can I modify a plank for wrist pain?"
                    className="w-full p-3 rounded-lg bg-gray-50 border-none focus:ring-2 focus:ring-navy mb-4 text-sm"
                    rows={3}
                />
                <Button onClick={handleAskConcierge} fullWidth disabled={loadingConcierge}>
                    {loadingConcierge ? 'Thinking...' : 'Ask Coach'}
                </Button>

                {conciergeAnswer && (
                    <div className="mt-6 p-4 bg-sand rounded-lg border border-navy/20">
                        <p className="text-sm text-charcoal leading-relaxed">{conciergeAnswer}</p>
                    </div>
                )}
            </div>
        </div>
      ) : (
        <div className="animate-[fadeIn_0.3s_ease-out]">
            <div className="mb-6">
                <h1 className="font-serif text-2xl text-charcoal mb-1">Session Planner</h1>
                <p className="text-xs text-orange font-bold uppercase tracking-widest">Instructor Grade • Beta</p>
            </div>

            {!sessionPlan ? (
            <div className="space-y-8 pb-10">

                {/* Section 1: Equipment */}
                <section>
                    <h3 className="text-sm font-bold text-navy uppercase tracking-wider mb-3">1. Select Apparatus</h3>
                    <div className="flex flex-wrap gap-2">
                        {EQUIPMENT_OPTIONS.map(item => (
                            <button
                                key={item}
                                onClick={() => toggleSelection(item, equipment, setEquipment)}
                                className={`px-3 py-2 text-xs rounded-md border transition-all duration-200 
                                ${equipment.includes(item) 
                                    ? 'bg-navy text-white border-navy shadow-md' 
                                    : 'bg-white text-gray-600 border-gray-200 hover:border-navy/50'}`}
                            >
                                {item}
                            </button>
                        ))}
                    </div>
                </section>

                {/* Section 2: Mood */}
                <section>
                    <h3 className="text-sm font-bold text-navy uppercase tracking-wider mb-3">2. Session Intent</h3>
                    <div className="grid grid-cols-1 gap-2">
                        {MOOD_OPTIONS.map(m => (
                            <button
                                key={m}
                                onClick={() => setMood(m)}
                                className={`px-4 py-3 text-sm rounded-lg border text-left flex justify-between items-center transition-all duration-200
                                ${mood === m 
                                    ? 'bg-orange/10 border-orange text-navy-dark font-medium shadow-inner' 
                                    : 'bg-white text-gray-600 border-gray-200 hover:bg-gray-50'}`}
                            >
                                {m}
                                {mood === m && <span className="text-orange">●</span>}
                            </button>
                        ))}
                    </div>
                </section>

                {/* Section 3: Issues */}
                <section>
                    <h3 className="text-sm font-bold text-navy uppercase tracking-wider mb-3">3. Considerations & Issues</h3>
                    <div className="flex flex-wrap gap-2 mb-4">
                        {ISSUE_OPTIONS.map(issue => (
                            <button
                                key={issue}
                                onClick={() => toggleSelection(issue, issues, setIssues)}
                                className={`px-3 py-1.5 text-xs rounded-full border transition-all duration-200
                                ${issues.includes(issue)
                                    ? 'bg-red-50 text-red-800 border-red-200 font-medium'
                                    : 'bg-white text-gray-500 border-gray-200'}`}
                            >
                                {issue}
                            </button>
                        ))}
                    </div>
                    <textarea
                        value={customNote}
                        onChange={(e) => setCustomNote(e.target.value)}
                        placeholder="Additional notes (e.g., 'Focus on scapular stability' or 'Client is recovering from ankle sprain')"
                        className="w-full p-3 rounded-lg bg-white border border-gray-200 focus:ring-1 focus:ring-navy text-sm shadow-sm"
                        rows={3}
                    />
                </section>

                <div className="pt-4">
                    <Button 
                        onClick={handleGeneratePlan} 
                        fullWidth 
                        size="lg" 
                        disabled={loadingPlan || equipment.length === 0 || !mood}
                        className="shadow-xl shadow-navy/20"
                    >
                        {loadingPlan ? 'Designing Session...' : 'GENERATE SESSION PLAN'}
                    </Button>
                    <p className="text-center text-[10px] text-gray-400 mt-3">
                        Generates a professional structure based on CoreKaya methodology.
                    </p>
                </div>
            </div>
            ) : (
                <div className="animate-[slideUp_0.5s_ease-out]">
                    <div className="bg-white rounded-2xl shadow-xl border border-gray-100 overflow-hidden">
                        <div className="bg-navy p-4 flex justify-between items-center sticky top-0 z-10">
                            <h2 className="text-white font-serif text-lg">Session Plan</h2>
                            <button 
                                onClick={() => setSessionPlan(null)}
                                className="text-white/70 text-xs hover:text-white uppercase font-bold"
                            >
                                New Plan
                            </button>
                        </div>
                        <div className="p-6 text-sm">
                            {renderPlanOutput(sessionPlan)}
                        </div>
                        <div className="p-4 bg-gray-50 border-t border-gray-100">
                             <Button onClick={() => setSessionPlan(null)} variant="outline" fullWidth>
                                 Start Over
                             </Button>
                        </div>
                    </div>
                </div>
            )}
        </div>
      )}
    </div>
  );
};

