                        ))}
                    </div>
                </section>

                {/* Section 3: Issues */}
                <section>
                    <h3 className="text-sm font-bold text-navy uppercase tracking-wider mb-3">3. Considerations & Issues</h3>
                    <div className="flex flex-wrap gap-2 mb-4">
